-- Supplier Risk Intelligence — synthetic external data
-- Run against warehouse c2abb17a6c9e6bc0 via Databricks SQL or deploy.sh

CREATE TABLE IF NOT EXISTS zivile.default.supplier_risk_scores (
  supplier_id STRING COMMENT 'SAP Supplier ID (matches PurchaseOrder.Supplier)',
  supplier_name STRING COMMENT 'Supplier company name',
  country STRING COMMENT 'Country of incorporation',
  industry STRING COMMENT 'Industry classification',
  abn STRING COMMENT 'Australian Business Number',
  credit_rating STRING COMMENT 'Credit rating (AAA to D)',
  credit_score INT COMMENT 'Numeric credit score (0-100)',
  financial_health_score DOUBLE COMMENT 'Composite financial health score (0-10)',
  risk_level STRING COMMENT 'Risk classification: Low, Medium, High, Critical',
  debt_to_equity_ratio DOUBLE COMMENT 'Debt-to-equity ratio',
  current_ratio DOUBLE COMMENT 'Current assets / current liabilities',
  annual_revenue_aud DOUBLE COMMENT 'Annual revenue in AUD',
  payment_default_history BOOLEAN COMMENT 'Whether supplier has any payment default history',
  sanctions_flagged BOOLEAN COMMENT 'Whether supplier is flagged on any sanctions list',
  esg_score DOUBLE COMMENT 'Environmental, Social, Governance score (0-100)',
  last_assessment_date DATE COMMENT 'Date of last risk assessment',
  next_review_date DATE COMMENT 'Scheduled next review date',
  assessor_notes STRING COMMENT 'Notes from the risk assessor'
) USING DELTA
COMMENT 'External supplier financial health and credit risk data — enriches SAP vendor master with third-party risk intelligence';

-- Truncate and re-insert for idempotency
TRUNCATE TABLE zivile.default.supplier_risk_scores;

